@ARTICLE{10.1016/j.stem.2025.05.015,
	author = {Lall, D. and Workman, M.J. and Sances, S. and Ondatje, B.N. and Bell, S. and Lawless, G. and Woodbury, A. and West, D. and Meyer, A. and Matlock, A. and Vaibhav, V. and Van Eyk, J.E. and Svendsen, C.N.},
	title = {An organ-chip model of sporadic ALS using iPSC-derived spinal cord motor neurons and an integrated blood-brain-like barrier},
	journal = {Cell Stem Cell},
	year = {2025},
	abstract = {Amyotrophic lateral sclerosis (ALS) is a fatal neurodegenerative disorder in which motor neurons (MNs) of the brain and spinal cord degenerate, leading to paralysis. Generating MNs from patient-specific induced pluripotent stem cells (iPSCs) may help elucidate early stages of disease. Here, we combined MNs from patients with early-onset disease with brain microvascular endothelial-like cells in a microfluidic device we termed spinal cord chips (SC-chips) and added media flow, which enhanced neuronal maturation and improved cellular health. Bulk transcriptomic and proteomic analyses of SC-chips revealed differences between control and ALS samples, including increased levels of neurofilaments. Single-nuclei RNA sequencing revealed the presence of two MN subpopulations and an ALS-specific dysregulation of glutamatergic and synaptic signaling. This ALS SC-chip model generates a diversity of mature MNs to better understand ALS pathology in a model that has an active blood-brain barrier-like system for future drug screening. © 2025 The Author(s) ER - ER - ER -},
	doi = {10.1016/j.stem.2025.05.015},
	type = {JOUR}
}

@ARTICLE{10.1016/j.stem.2024.04.019,
	author = {Dao, L. and You, Z. and Lu, L. and Xu, T. and Sarkar, A.K. and Zhu, H. and Liu, M. and Calandrelli, R. and Yoshida, G. and Lin, P. and Miao, Y. and Mierke, S. and Kalva, S. and Zhu, H. and Gu, M. and Vadivelu, S. and Zhong, S. and Huang, L.F. and Guo, Z.},
	title = {Modeling blood-brain barrier formation and cerebral cavernous malformations in human PSC-derived organoids},
	journal = {Cell Stem Cell},
	year = {2024},
	abstract = {The human blood-brain barrier (hBBB) is a highly specialized structure that regulates passage across blood and central nervous system (CNS) compartments. Despite its critical physiological role, there are no reliable in vitro models that can mimic hBBB development and function. Here, we constructed hBBB assembloids from brain and blood vessel organoids derived from human pluripotent stem cells. We validated the acquisition of blood-brain barrier (BBB)-specific molecular, cellular, transcriptomic, and functional characteristics and uncovered an extensive neuro-vascular crosstalk with a spatial pattern within hBBB assembloids. When we used patient-derived hBBB assembloids to model cerebral cavernous malformations (CCMs), we found that these assembloids recapitulated the cavernoma anatomy and BBB breakdown observed in patients. Upon comparison of phenotypes and transcriptome between patient-derived hBBB assembloids and primary human cavernoma tissues, we uncovered CCM-related molecular and cellular alterations. Taken together, we report hBBB assembloids that mimic the core properties of the hBBB and identify a potentially underlying cause of CCMs. © 2024 Elsevier Inc. ER - ER - ER -},
	doi = {10.1016/j.stem.2024.04.019},
	type = {JOUR}
}

@ARTICLE{10.1038/s41593-025-02123-w,
	author = {González-Gallego, J. and Todorov-Völgyi, K. and Müller, S.A. and Antesberger, S. and Todorov, M.I. and Malik, R. and Grimalt-Mirada, R. and Gonçalves, C.C. and Schifferer, M. and Kislinger, G. and Weisheit, I. and Lindner, B. and Crusius, D. and Kroeger, J. and Borri, M. and Erturk, A. and Nelson, M. and Misgeld, T. and Lichtenthaler, S.F. and Dichgans, M. and Paquet, D.},
	title = {A fully iPS-cell-derived 3D model of the human blood–brain barrier for exploring neurovascular disease mechanisms and therapeutic interventions},
	journal = {Nature Neuroscience},
	year = {2026},
	abstract = {Blood–brain barrier (BBB) integrity is critical for brain homeostasis, with malfunctions contributing to neurovascular and neurodegenerative disorders. Mechanistic studies on BBB function have been mostly conducted in rodent and in vitro models, which recapitulate some disease features, but have limited translatability to humans and pose challenges for drug discovery. Here we report on a fully human induced pluripotent stem (iPS)-cell-derived, microfluidic three-dimensional (3D) BBB model consisting of endothelial cells (ECs), mural cells and astrocytes. Our model expresses typical fate markers, forms a barrier in vessel-like tubes and enables perfusion, including with human blood. Deletion of FOXF2 in ECs, a major risk gene for cerebral small vessel disease, induced key features of BBB dysfunction, including compromised cell junction integrity and enhanced caveolae formation. Proteomic analysis revealed dysregulated endocytosis and cell junction pathways. Disease features phenocopied those seen in mice with EC-specific Foxf2 deficiency. Moreover, lipid-nanoparticle-based treatment with Foxf2 mRNA rescued BBB deficits, demonstrating the potential for drug development. © The Author(s) 2025. ER - ER - ER -},
	doi = {10.1038/s41593-025-02123-w},
	type = {JOUR}
}

@ARTICLE{10.1038/s41564-025-02000-z,
	author = {Zhao, H. and Catarino, J. and Stack, G. and Albizu, A.K. and Lara-Tejero, M. and Horvath, T.L. and Galán, J.E.},
	title = {Typhoid toxin causes neuropathology by disrupting the blood–brain barrier},
	journal = {Nature Microbiology},
	year = {2025},
	abstract = {Typhoid fever, primarily caused by Salmonella Typhi, can result in severe life-threatening complications such as encephalopathy. Here we elucidate the mechanisms by which typhoid toxin, a unique virulence factor of S. Typhi, mediates the neuropathology associated with typhoid fever. Utilizing mice engineered to have specific tissues protected from toxin action and an in vitro model of the blood–brain barrier (BBB), we demonstrate that, rather than direct action on neuronal or glial cells, typhoid toxin causes neuropathology by disrupting the BBB. Intravenous tracer studies confirmed significant BBB permeability changes following toxin exposure, an effect we found to be mediated by typhoid toxin’s CdtB catalytic subunit. We demonstrate that corticosteroids are effective at mitigating BBB disruption in vivo, supporting their use for managing typhoid fever neurological complications. Our data reveal mechanistic insight into how typhoid toxin causes encephalopathy and suggest targeted therapeutic interventions to alleviate the severe neurological manifestations of typhoid fever. © The Author(s), under exclusive licence to Springer Nature Limited 2025. ER - ER - ER -},
	doi = {10.1038/s41564-025-02000-z},
	type = {JOUR}
}

@ARTICLE{10.1126/sciadv.aaz9499,
	author = {Winkelman, M.A. and Dai, G.},
	title = {Bioengineered perfused human brain microvascular networks enhance neural progenitor cell survival, neurogenesis, and maturation},
	journal = {Science Advances},
	year = {2023},
	abstract = {Neural progenitor cells (NPCs) have the capability to self-renew and differentiate into neurons and glial cells. In the adult brain, NPCs are found near brain microvascular networks (BMVNs) in specialized microenvironments called the neurovascular niche (NVN). Although several in vitro NVN models have been previously reported, most do not properly recapitulate the intimate cellular interactions between NPCs and perfused brain microvessels. Here, we developed perfused BMVNs composed of primary human brain endothelial cells, pericytes, and astrocytes within microfluidic devices. When induced pluripotent stem cell-derived NPCs were introduced into BMVNs, we found that NPC survival, neurogenesis, and maturation were enhanced. The application of flow during BMVN coculture was also beneficial for neuron differentiation. Collectively, our work highlighted the important role of BMVNs and flow in NPC self-renewal and neurogenesis, as well as demonstrated our model's potential to study the biological and physical interactions of human NVN in vitro. 2023 The Authors. © 2023 American Association for the Advancement of Science. All rights reserved. ER - ER - ER -},
	doi = {10.1126/sciadv.aaz9499},
	type = {JOUR}
}

@ARTICLE{10.1016/j.celrep.2022.110885,
	author = {Cheng, Y. and Medina, A. and Yao, Z. and Basu, M. and Natekar, J.P. and Lang, J. and Sanchez, E. and Nkembo, M.B. and Xu, C. and Qian, X. and Nguyen, P.T.T. and Wen, Z. and Song, H. and Ming, G.-L. and Kumar, M. and Brinton, M.A. and Li, M.M.H. and Tang, H.},
	title = {Intrinsic antiviral immunity of barrier cells revealed by an iPSC-derived blood-brain barrier cellular model},
	journal = {Cell Reports},
	year = {2022},
	abstract = {Physiological blood-tissue barriers play a critical role in separating the circulation from immune-privileged sites and denying access to blood-borne viruses. The mechanism of virus restriction by these barriers is poorly understood. We utilize induced pluripotent stem cell (iPSC)-derived human brain microvascular endothelial cells (iBMECs) to study virus-blood-brain barrier (BBB) interactions. These iPSC-derived cells faithfully recapitulate a striking difference in in vivo neuroinvasion by two alphavirus isolates and are selectively permissive to neurotropic flaviviruses. A model of cocultured iBMECs and astrocytes exhibits high transendothelial electrical resistance and blocks non-neurotropic flaviviruses from getting across the barrier. We find that iBMECs constitutively express an interferon-induced gene, IFITM1, which preferentially restricts the replication of non-neurotropic flaviviruses. Barrier cells from blood-testis and blood-retinal barriers also constitutively express IFITMs that contribute to the viral resistance. Our application of a renewable human iPSC-based model for studying virus-BBB interactions reveals that intrinsic immunity at the barriers contributes to virus exclusion. © 2022 The Author(s) ER - ER - ER -},
	doi = {10.1016/j.celrep.2022.110885},
	type = {JOUR}
}

@ARTICLE{10.1038/s41467-023-39038-8,
	author = {de Rus Jacquet, A. and Alpaugh, M. and Denis, H.L. and Tancredi, J.L. and Boutin, M. and Decaestecker, J. and Beauparlant, C. and Herrmann, L. and Saint-Pierre, M. and Parent, M. and Droit, A. and Breton, S. and Cicchetti, F.},
	title = {The contribution of inflammatory astrocytes to BBB impairments in a brain-chip model of Parkinson’s disease},
	journal = {Nature Communications},
	year = {2023},
	abstract = {Astrocyte dysfunction has previously been linked to multiple neurodegenerative disorders including Parkinson’s disease (PD). Among their many roles, astrocytes are mediators of the brain immune response, and astrocyte reactivity is a pathological feature of PD. They are also involved in the formation and maintenance of the blood-brain barrier (BBB), but barrier integrity is compromised in people with PD. This study focuses on an unexplored area of PD pathogenesis by characterizing the interplay between astrocytes, inflammation and BBB integrity, and by combining patient-derived induced pluripotent stem cells with microfluidic technologies to generate a 3D human BBB chip. Here we report that astrocytes derived from female donors harboring the PD-related LRRK2 G2019S mutation are pro-inflammatory and fail to support the formation of a functional capillary in vitro. We show that inhibition of MEK1/2 signaling attenuates the inflammatory profile of mutant astrocytes and rescues BBB formation, providing insights into mechanisms regulating barrier integrity in PD. Lastly, we confirm that vascular changes are also observed in the human postmortem substantia nigra of both males and females with PD. © 2023, The Author(s). ER - ER - ER -},
	doi = {10.1038/s41467-023-39038-8},
	type = {JOUR}
}
